head.script:
scwin.onSearchCode = "INIT";
scwin.vToDate = "";
scwin.vCurDate = "";
scwin.strCurDate = "";
scwin.strQryStDt = "";
scwin.UserID = "";
scwin.UserName = "";
scwin.HdofficeIdx = 0;
scwin.BhofficeIdx = 0;
scwin.OfficeIdx = 0;
scwin.csVl3 = "";
scwin.csVl4 = "";
scwin.fl_masteridx = "";
scwin.fl_subidx = "";
scwin.fl_type = "";
scwin.txt_vehclShortCd = "";
scwin.txt_vehclNos = "";
scwin.selectedvehclRow = "";
scwin.ez110Idx = "";
scwin.vehclType = "";
scwin.msgFlag = "false";

scwin.onpageload = function() {
    scwin.vToDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.strCurDate = scwin.vCurDate;
    scwin.strQryStDt = scwin.strCurDate.substring(0, 6) + "01";

    scwin.UserID = $c.ses.getUserId();
    scwin.UserName = $c.ses.getUserNm();
    // TODO: HdofficeIdx, BhofficeIdx, OfficeIdx는 서버 세션에서 가져와야 함
    scwin.HdofficeIdx = 0;
    scwin.BhofficeIdx = 0;
    scwin.OfficeIdx = 0;
};

scwin.onUdcCompleted = function() {
    scwin.f_reflashdata();
};

scwin.f_reflashdata = function() {
    let parentWin = $p.parent();
    if (parentWin && parentWin.scwin && typeof parentWin.scwin.reflashdata === "function") {
        parentWin.scwin.reflashdata();
    }
};

scwin.f_chkOpenCommonPopUp = function(inObjId, pairObjId, disGubun, isCode) {
    let inVal = "";
    let pairVal = "";
    if (inObjId === "txt_vehclShortCd") {
        inVal = scwin.txt_vehclShortCd;
    } else if (inObjId === "txt_vehclNos") {
        inVal = scwin.txt_vehclNos;
    }

    if (inVal == "") return;

    if (pairObjId === "txt_vehclNos") {
        scwin.txt_vehclNos = "";
    } else if (pairObjId === "txt_vehclShortCd") {
        scwin.txt_vehclShortCd = "";
    }

    let pVal = inVal;

    if (isCode == null || isCode == true) {
        scwin.f_openPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        scwin.f_openPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

scwin.f_openPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    if (disGubun == "1") {
        udc_vehclShort.ilCommonPopUp(scwin.callbackVehclPopUp,
            pCode,
            pName,
            pClose,
            null,
            null,
            null,
            null,
            null,
            "400",
            null,
            null,
            null,
            null,
            pAllSearch,
            "차량번호,차량단축코드,차량번호"
        );
    }
};

scwin.callbackVehclPopUp = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, txt_vehclShortCd, txt_vehclNos);
};

scwin.f_eventRadioClick = function(No) {
    let toDate = scwin.vToDate;
    let toYear = toDate.toString().substring(0, 4);
    let toMonth = toDate.toString().substring(4, 6);
    let toDay = toDate.toString().substring(6, 8);

    let toYearDt1, toYearDt2;
    let toMonthDt1, toMonthDt2;
    let toDayDt1, toDayDt2;
    let sDt1, sDt2;

    let NowDate = new Date(parseInt(toYear), parseInt(toMonth) - 1, parseInt(toDay));

    switch (No) {
        case '1': {
            scwin.csVl3 = toDate;
            scwin.csVl4 = toDate;
            break;
        }
        case '2': {
            let numb = NowDate.getTime();
            let TempDay = NowDate.getDay();
            let TempDate = NowDate;

            TempDate.setTime(numb - (TempDay * 1000 * 60 * 60 * 24));
            toYearDt1 = TempDate.getFullYear();
            toMonthDt1 = TempDate.getMonth() + 1;
            toDayDt1 = TempDate.getDate();
            toMonthDt1 = '0' + toMonthDt1;
            toMonthDt1 = toMonthDt1.substr(toMonthDt1.length - 2, toMonthDt1.length);
            toDayDt1 = '0' + toDayDt1;
            toDayDt1 = toDayDt1.substr(toDayDt1.length - 2, toDayDt1.length);
            sDt1 = toYearDt1.toString() + toMonthDt1.toString() + toDayDt1.toString();

            TempDate.setTime(numb + ((6 - TempDay) * 1000 * 60 * 60 * 24));
            toYearDt2 = TempDate.getFullYear();
            toMonthDt2 = TempDate.getMonth() + 1;
            toDayDt2 = TempDate.getDate();
            toMonthDt2 = '0' + toMonthDt2;
            toMonthDt2 = toMonthDt2.substr(toMonthDt2.length - 2, toMonthDt2.length);
            toDayDt2 = '0' + toDayDt2;
            toDayDt2 = toDayDt2.substr(toDayDt2.length - 2, toDayDt2.length);
            sDt2 = toYearDt2.toString() + toMonthDt2.toString() + toDayDt2.toString();

            scwin.csVl3 = sDt1;
            scwin.csVl4 = sDt2;
            break;
        }
        case '3': {
            let numb3 = NowDate.getTime();
            let TempDate3 = NowDate;
            toMonthDt1 = NowDate.getMonth() + 1;
            toYearDt1 = TempDate3.getFullYear();
            toMonthDt1 = '0' + toMonthDt1;
            toMonthDt1 = toMonthDt1.substr(toMonthDt1.length - 2, toMonthDt1.length);
            toDayDt1 = '01';
            sDt1 = toYearDt1.toString() + toMonthDt1.toString() + toDayDt1.toString();

            TempDate3 = new Date(toYearDt1, TempDate3.getMonth() + 1, toDayDt1);
            TempDate3.setTime(TempDate3.getTime() - (1 * 1000 * 60 * 60 * 24));

            toYearDt2 = TempDate3.getFullYear();
            toMonthDt2 = TempDate3.getMonth();
            toMonthDt2 = '0' + toMonthDt1;
            toMonthDt2 = toMonthDt2.substr(toMonthDt2.length - 2, toMonthDt2.length);
            toDayDt2 = TempDate3.getDate();
            toDayDt2 = '0' + toDayDt2;
            toDayDt2 = toDayDt2.substr(toDayDt2.length - 2, toDayDt2.length);
            sDt2 = toYearDt2.toString() + toMonthDt2.toString() + toDayDt2.toString();

            scwin.csVl3 = sDt1;
            scwin.csVl4 = sDt2;
            break;
        }
        case '4': {
            let numb4 = NowDate.getTime();
            let TempDate4 = NowDate;
            toMonthDt1 = NowDate.getMonth();
            toYearDt1 = TempDate4.getFullYear();
            toMonthDt1 = '0' + toMonthDt1;
            toMonthDt1 = toMonthDt1.substr(toMonthDt1.length - 2, toMonthDt1.length);
            toDayDt1 = '01';
            sDt1 = toYearDt1.toString() + toMonthDt1.toString() + toDayDt1.toString();

            TempDate4 = new Date(toYearDt1, TempDate4.getMonth(), toDayDt1);
            TempDate4.setTime(TempDate4.getTime() - (1 * 1000 * 60 * 60 * 24));

            toYearDt2 = TempDate4.getFullYear();
            toMonthDt2 = TempDate4.getMonth();
            toMonthDt2 = '0' + toMonthDt1;
            toMonthDt2 = toMonthDt2.substr(toMonthDt2.length - 2, toMonthDt2.length);
            toDayDt2 = TempDate4.getDate();
            toDayDt2 = '0' + toDayDt2;
            toDayDt2 = toDayDt2.substr(toDayDt2.length - 2, toDayDt2.length);
            sDt2 = toYearDt2.toString() + toMonthDt2.toString() + toDayDt2.toString();

            scwin.csVl3 = sDt1;
            scwin.csVl4 = sDt2;
            break;
        }
        case '5': {
            break;
        }
    }
};

scwin.search_car = async function(str) {
    scwin.selectedvehclRow = '';
    scwin.ez110Idx = '';
    scwin.vehclType = str;

    let condData = scwin.f_getCondData();

    scwin.f_eventRadioClick(condData.vehclDateTyp);

    dma_search_car.set("vehclDateTyp", condData.vehclDateTyp);
    dma_search_car.set("vehclDateCnd", condData.vehclDateCnd);
    if (condData.vehclDateTyp == 5) {
        dma_search_car.set("vehclDate1", condData.vehclDate1);
        dma_search_car.set("vehclDate2", condData.vehclDate2);
    } else {
        dma_search_car.set("vehclDate1", scwin.csVl3.trim());
        dma_search_car.set("vehclDate2", scwin.csVl4.trim());
    }

    dma_search_car.set("vehclSts1", condData.vehclSts1);
    dma_search_car.set("vehclSts2", condData.vehclSts2);
    dma_search_car.set("vehclSts3", condData.vehclSts3);
    dma_search_car.set("vehclSts4", condData.vehclSts4);
    dma_search_car.set("vehclHdidx", condData.vehclHdidx);
    dma_search_car.set("vehclBhidx", condData.vehclBhidx);
    dma_search_car.set("vehclOfcidx", condData.vehclOfcidx);

    let ord = 0;
    dma_search_car.set("vehclOrd1", condData.vehclOrd1);
    dma_search_car.set("vehclOrdAsc1", condData.vehclOrdAsc1);
    dma_search_car.set("vehclOrdUsr1", condData.vehclOrdUsr1);
    dma_search_car.set("vehclOrd2", condData.vehclOrd2);
    dma_search_car.set("vehclOrdAsc2", condData.vehclOrdAsc2);
    dma_search_car.set("vehclOrdUsr2", condData.vehclOrdUsr2);
    dma_search_car.set("vehclOrd3", condData.vehclOrd3);
    dma_search_car.set("vehclOrdAsc3", condData.vehclOrdAsc3);
    dma_search_car.set("vehclOrdUsr3", condData.vehclOrdUsr3);

    if (condData.vehclOrdUsr1 > 0) {
        ord += 1;
    }
    if (condData.vehclOrdUsr2 > 0) {
        ord += 2;
    }
    if (condData.vehclOrdUsr3 > 0) {
        ord += 4;
    }
    dma_search_car.set("ord", ord.toString());
    dma_search_car.set("vehclSellClntNo", condData.vehclSellClntNo);

    scwin.vehclType = str;
    scwin.selectedvehclRow = '';

    if (str == 'all') {
        dma_search_car.set("carNo", scwin.txt_vehclNos);
        dma_search_car.set("blkCntrCls", "");
        if (scwin.onSearchCode == "INIT" || scwin.onSearchCode == "END") {
            scwin.onSearchCode = "START";
            await $c.sbm.execute(sbm_search_car_all);
        } else {
            await $c.win.alert("차량 조회중 입니다. 잠시후 다시 시도해 주세요");
            return false;
        }
    } else if (str == 'blk') {
        dma_search_car.set("blkCntrCls", "1");
        if (scwin.onSearchCode == "INIT" || scwin.onSearchCode == "END") {
            scwin.onSearchCode = "START";
            await $c.sbm.execute(sbm_search_car_blk);
        } else {
            await $c.win.alert("차량 조회중 입니다. 잠시후 다시 시도해 주세요");
            return false;
        }
    } else if (str == 'cntr') {
        dma_search_car.set("blkCntrCls", "2");
        if (scwin.onSearchCode == "INIT" || scwin.onSearchCode == "END") {
            scwin.onSearchCode = "START";
            await $c.sbm.execute(sbm_search_car_cntr);
        } else {
            await $c.win.alert("차량 조회중 입니다. 잠시후 다시 시도해 주세요");
            return false;
        }
    } else if (str == 'matching') {
        if (scwin.onSearchCode == "INIT" || scwin.onSearchCode == "END") {
            scwin.onSearchCode = "START";
            await $c.sbm.execute(sbm_search_car_matching);
        } else {
            await $c.win.alert("차량 조회중 입니다. 잠시후 다시 시도해 주세요");
            return false;
        }
    } else if (str == 'mb') {
        if (scwin.onSearchCode == "INIT" || scwin.onSearchCode == "END") {
            scwin.onSearchCode = "START";
            await $c.sbm.execute(sbm_search_car_mb);
        } else {
            await $c.win.alert("차량 조회중 입니다. 잠시후 다시 시도해 주세요");
            return false;
        }
    } else if (str == 'tab6') {
        scwin.f_retrieve_openPublic();
    } else {
        if (scwin.onSearchCode == "INIT" || scwin.onSearchCode == "END") {
            scwin.onSearchCode = "START";
            await $c.sbm.execute(sbm_search_car_mb);
        } else {
            await $c.win.alert("차량 조회중 입니다. 잠시후 다시 시도해 주세요");
            return false;
        }
    }
};

scwin.f_getCondData = function() {
    let condData = {
        vehclDateTyp: "",
        vehclDateCnd: "",
        vehclDate1: "",
        vehclDate2: "",
        vehclSts1: "",
        vehclSts2: "",
        vehclSts3: "",
        vehclSts4: "",
        vehclHdidx: "",
        vehclBhidx: "",
        vehclOfcidx: "",
        vehclOrd1: "",
        vehclOrdAsc1: "",
        vehclOrdUsr1: 0,
        vehclOrd2: "",
        vehclOrdAsc2: "",
        vehclOrdUsr2: 0,
        vehclOrd3: "",
        vehclOrdAsc3: "",
        vehclOrdUsr3: 0,
        vehclSellClntNo: ""
    };
    let parentWin = $p.parent();
    if (parentWin && parentWin.scwin && parentWin.scwin.ds_cond) {
        let pDs = parentWin.scwin.ds_cond;
        condData.vehclDateTyp = pDs.get("vehclDateTyp") || "";
        condData.vehclDateCnd = pDs.get("vehclDateCnd") || "";
        condData.vehclDate1 = pDs.get("vehclDate1") || "";
        condData.vehclDate2 = pDs.get("vehclDate2") || "";
        condData.vehclSts1 = pDs.get("vehclSts1") || "";
        condData.vehclSts2 = pDs.get("vehclSts2") || "";
        condData.vehclSts3 = pDs.get("vehclSts3") || "";
        condData.vehclSts4 = pDs.get("vehclSts4") || "";
        condData.vehclHdidx = pDs.get("vehclHdidx") || "";
        condData.vehclBhidx = pDs.get("vehclBhidx") || "";
        condData.vehclOfcidx = pDs.get("vehclOfcidx") || "";
        condData.vehclOrd1 = pDs.get("vehclOrd1") || "";
        condData.vehclOrdAsc1 = pDs.get("vehclOrdAsc1") || "";
        condData.vehclOrdUsr1 = parseInt(pDs.get("vehclOrdUsr1")) || 0;
        condData.vehclOrd2 = pDs.get("vehclOrd2") || "";
        condData.vehclOrdAsc2 = pDs.get("vehclOrdAsc2") || "";
        condData.vehclOrdUsr2 = parseInt(pDs.get("vehclOrdUsr2")) || 0;
        condData.vehclOrd3 = pDs.get("vehclOrd3") || "";
        condData.vehclOrdAsc3 = pDs.get("vehclOrdAsc3") || "";
        condData.vehclOrdUsr3 = parseInt(pDs.get("vehclOrdUsr3")) || 0;
        condData.vehclSellClntNo = pDs.get("vehclSellClntNo") || "";
    }
    return condData;
};

scwin.openmap = async function() {
    let condition = {};
    let activeTab = tac_tabControl1.getSelectedTabIndex();

    if (activeTab == 1) {
        let row = ds_car_blk.getRowPosition();
        if (row < 0) return;
        condition.CARNO = ds_car_blk.getCellData(row, 'vehclNo');
        condition.CARSTS = ds_car_blk.getCellData(row, 'vehclSts');
        condition.USRNM = ds_car_blk.getCellData(row, 'picNm');
        condition.PHONENO = ds_car_blk.getCellData(row, 'handphoneNo');
        condition.POST = ds_car_blk.getCellData(row, 'posTxt');
        condition.TIME = ds_car_blk.getCellData(row, 'txnDate');
        condition.CARTYPE = ds_car_blk.getCellData(row, 'vehclNo');
        condition.XPOS = ds_car_blk.getCellData(row, 'xpos');
        condition.YPOS = ds_car_blk.getCellData(row, 'ypos');
    } else if (activeTab == 2) {
        let row = ds_car_cntr.getRowPosition();
        if (row < 0) return;
        condition.CARNO = ds_car_cntr.getCellData(row, 'vehclNo');
        condition.CARSTS = ds_car_cntr.getCellData(row, 'vehclSts');
        condition.USRNM = ds_car_cntr.getCellData(row, 'picNm');
        condition.PHONENO = ds_car_cntr.getCellData(row, 'handphoneNo');
        condition.POST = ds_car_cntr.getCellData(row, 'posTxt');
        condition.TIME = ds_car_cntr.getCellData(row, 'txnDate');
        condition.CARTYPE = ds_car_cntr.getCellData(row, 'vehclNo');
        condition.XPOS = ds_car_cntr.getCellData(row, 'xpos');
        condition.YPOS = ds_car_cntr.getCellData(row, 'ypos');
    } else if (activeTab == 3) {
        let row = ds_car_mb.getRowPosition();
        if (row < 0) return;
        condition.CARNO = ds_car_mb.getCellData(row, 'vehclNo');
        condition.CARSTS = ds_car_mb.getCellData(row, 'vehclSts');
        condition.USRNM = ds_car_mb.getCellData(row, 'picNm');
        condition.PHONENO = ds_car_mb.getCellData(row, 'handphoneNo');
        condition.POST = ds_car_mb.getCellData(row, 'posTxt');
        condition.TIME = ds_car_mb.getCellData(row, 'txnDate');
        condition.CARTYPE = ds_car_mb.getCellData(row, 'vehclNo');
        condition.XPOS = ds_car_mb.getCellData(row, 'xpos');
        condition.YPOS = ds_car_mb.getCellData(row, 'ypos');
    } else {
        let row = ds_car.getRowPosition();
        if (row < 0) return;
        condition.CARNO = ds_car.getCellData(row, 'vehclNo');
        condition.CARSTS = ds_car.getCellData(row, 'vehclSts');
        condition.USRNM = ds_car.getCellData(row, 'picNm');
        condition.PHONENO = ds_car.getCellData(row, 'handphoneNo');
        condition.POST = ds_car.getCellData(row, 'posTxt');
        condition.TIME = ds_car.getCellData(row, 'txnDate');
        condition.CARTYPE = ds_car.getCellData(row, 'vehclNo');
        condition.XPOS = ds_car.getCellData(row, 'xpos');
        condition.YPOS = ds_car.getCellData(row, 'ypos');
    }

    await $c.win.openPopup("/ui/lbs/yb/yb/lbs_326_02_02p.xml", {
        width: 500,
        height: 660,
        modal: false,
        data: condition
    });
};

scwin.showmbcar = async function(ton, dt) {
    scwin.selectedvehclRow = '';
    scwin.ez110Idx = '';
    scwin.vehclType = 'mb';

    if (typeof ton === 'undefined' || ton == null) {
        ton = "0";
    }
    if (typeof dt === 'undefined' || dt == null) {
        dt = scwin.vToDate;
    }
    dt = dt.replace("-", "");
    dt = dt.replace("-", "");

    let condData = scwin.f_getCondData();

    dma_search_car.set("ton", ton);
    dma_search_car.set("dt", dt);
    dma_search_car.set("vehclHdidx", condData.vehclHdidx);
    dma_search_car.set("vehclBhidx", condData.vehclBhidx);
    dma_search_car.set("vehclOfcidx", condData.vehclOfcidx);

    await $c.sbm.execute(sbm_search_car_mb);
};

scwin.showmbrequestcar = async function(fl_masteridx_val, fl_subidx_val, fl_type_val) {
    scwin.selectedvehclRow = '';
    scwin.ez110Idx = '';
    scwin.vehclType = 'matching';

    scwin.fl_masteridx = fl_masteridx_val;
    scwin.fl_subidx = fl_subidx_val;
    scwin.fl_type = fl_type_val;

    dma_search_car.set("idx", fl_masteridx_val);
    if (fl_type_val == 'cont') {
        dma_search_car.set("cntr", fl_subidx_val);
        dma_search_car.set("blk", "");
    } else if (fl_type_val == 'cargo') {
        dma_search_car.set("blk", fl_subidx_val);
        dma_search_car.set("cntr", "");
    }

    // TODO: GetCookie('csVl2'), GetCookie('csVl5') 대체 필요
    let csVl2Val = "";
    let csVl5Val = "";
    scwin.f_eventRadioClick(csVl2Val.trim());
    dma_search_car.set("dateOp", csVl5Val.trim());
    dma_search_car.set("dateCond1", scwin.csVl3.trim());
    dma_search_car.set("dateCond2", scwin.csVl4.trim());

    await $c.sbm.execute(sbm_search_car_matching);
};

scwin.checkSub = async function(idx) {
    let vFlType;
    let idxs = idx.split("-");
    let cars = "";
    let vehclTypeVal = scwin.vehclType;

    switch (vehclTypeVal) {
        case 'all':
            for (let RowCount = 0; RowCount < ds_car.getRowCount(); RowCount++) {
                if (ds_car.getRowMark(RowCount)) {
                    cars += ds_car.getCellData(RowCount, "ez110Idx") + ',';
                }
            }
            break;
        case 'blk':
            for (let RowCount = 0; RowCount < ds_car_blk.getRowCount(); RowCount++) {
                if (ds_car_blk.getRowMark(RowCount)) {
                    cars += ds_car_blk.getCellData(RowCount, "ez110Idx") + ',';
                }
            }
            break;
        case 'cntr':
            for (let RowCount = 0; RowCount < ds_car_cntr.getRowCount(); RowCount++) {
                if (ds_car_cntr.getRowMark(RowCount)) {
                    cars += ds_car_cntr.getCellData(RowCount, "ez110Idx") + ',';
                }
            }
            break;
        case 'matching':
            for (let RowCount = 0; RowCount < ds_car_matching.getRowCount(); RowCount++) {
                if (ds_car_matching.getRowMark(RowCount)) {
                    cars += ds_car_matching.getCellData(RowCount, "ez110Idx") + ',';
                }
            }
            break;
        case 'mb':
            for (let RowCount = 0; RowCount < ds_car_mb.getRowCount(); RowCount++) {
                if (ds_car_mb.getRowMark(RowCount)) {
                    cars += ds_car_mb.getCellData(RowCount, "ez110Idx") + ',';
                }
            }
            break;
        case 'tab6':
            for (let RowCount = 0; RowCount < ds_openPublic.getRowCount(); RowCount++) {
                if (ds_openPublic.getRowMark(RowCount)) {
                    cars += ds_openPublic.getCellData(RowCount, "ez110Idx") + ',';
                }
            }
            break;
    }

    let parentWin = $p.parent();
    if (parentWin && parentWin.scwin) {
        let topDiv1Visible = parentWin.scwin.topDiv1Visible;
        if (topDiv1Visible === true || topDiv1Visible === "visible") {
            vFlType = "1";
        } else {
            vFlType = "2";
        }
    } else {
        vFlType = "1";
    }

    cars = cars.substring(0, cars.length - 1);
    cars = cars.split(",");

    ds_car_allocar_sub.removeAll();

    for (let i = 0; i < cars.length; i++) {
        let newRow = ds_car_allocar_sub.insertRow();
        ds_car_allocar_sub.setCellData(newRow, "flType", vFlType);
        ds_car_allocar_sub.setCellData(newRow, "flMasterIdx", idxs[0]);
        ds_car_allocar_sub.setCellData(newRow, "flDetailIdx", idxs[1]);
        ds_car_allocar_sub.setCellData(newRow, "flCarIdx", cars[i]);
    }

    await $c.sbm.execute(sbm_car_allocar_sub);
};

scwin.goIdx = function() {
    let parentWin = $p.parent();
    if (parentWin && parentWin.scwin && typeof parentWin.scwin.getIdx === "function") {
        parentWin.scwin.getIdx();
    }
};

scwin.f_retrieve_openPublic = async function() {
    dma_openPublic_cond.set("openDate", ed_openDate.getValue().trim());
    dma_openPublic_cond.set("city", txt_do.getValue().trim());
    dma_openPublic_cond.set("vehclNo", txt_vehclNo.getValue().trim());

    if (dma_openPublic_cond.get("openDate") == "") {
        await $c.win.alert("공개일자는 필수 조회 조건입니다");
        ed_openDate.setFocus();
        return false;
    }

    scwin.selectedvehclRow = '';
    scwin.ez110Idx = '';
    scwin.vehclType = "public";

    await $c.sbm.execute(sbm_openPublic);
};

scwin.f_openEmptyCarPopup = async function(dsObj, rowIndex) {
    if (rowIndex < 0) return;
    let param = {
        mtvehclDd: dsObj.getCellData(rowIndex, 'mtvehclDd'),
        ez110Idx: dsObj.getCellData(rowIndex, 'ez110Idx'),
        ofcNm: dsObj.getCellData(rowIndex, 'ofcNm'),
        vehclNo: dsObj.getCellData(rowIndex, 'vehclNo'),
        handphoneNo: dsObj.getCellData(rowIndex, 'handphoneNo'),
        picNm: dsObj.getCellData(rowIndex, 'picNm'),
        tonCdNm: dsObj.getCellData(rowIndex, 'tonCdNm'),
        typeCdNm: dsObj.getCellData(rowIndex, 'typeCdNm')
    };
    await $c.win.openPopup("/ui/bp/fbp/op/ac/ez_200_01_01p.xml", {
        width: 570,
        height: 425,
        modal: false,
        data: param
    });
};

scwin.sbm_car_allocar_sub_submitdone = async function(e) {
    let row = ds_result.getRowPosition();
    if (row >= 0) {
        let outMsg = ds_result.getCellData(row, "outMsg");
        if (outMsg != null && outMsg != "") {
            await $c.win.alert(outMsg);
        }
    }
};

