scwin.ds_car_matching_oncelldatachange = async function(info) {
    let row = info.row;
    let colid = info.colId;
    if (colid == 'yesno') {
        ds_car_req.removeAll();
        let newRow = ds_car_req.insertRow();
        ds_car_req.setCellData(newRow, "ez222Idx", ds_car_matching.getCellData(row, 'ez222Idx'));
        ds_car_req.setCellData(newRow, "yesno", ds_car_matching.getCellData(row, 'yesno'));
        await $c.sbm.execute(sbm_car_req);
    }
};

