scwin.tac_tabControl1_onchange = function(tabIndex) {
    switch (tabIndex) {
        case 0:
            scwin.search_car('all');
            break;
        case 1:
            scwin.search_car('blk');
            break;
        case 2:
            scwin.search_car('cntr');
            break;
        case 3:
            scwin.search_car('mb');
            break;
    }
};

